package integration

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/grpc-ecosystem/grpc-gateway/v2/runtime"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"go.flipt.io/flipt/internal/server/evaluation"
	"go.flipt.io/flipt/internal/storage"
	"go.flipt.io/flipt/rpc/flipt"
	rpcevaluation "go.flipt.io/flipt/rpc/flipt/evaluation"
	"go.uber.org/zap/zaptest"
)

// setupEvaluationServer creates a test HTTP server with the evaluation service registered
func setupEvaluationServer(t *testing.T, store evaluation.Storer) *httptest.Server {
	mux := runtime.NewServeMux()
	ctx := context.Background()

	server := evaluation.New(zaptest.NewLogger(t), store)
	err := rpcevaluation.RegisterEvaluationServiceHandlerServer(ctx, mux, server)
	require.NoError(t, err, "failed to register evaluation service handler")

	return httptest.NewServer(mux)
}

// TestBooleanEvaluationSuccess tests a successful boolean flag evaluation
func TestBooleanEvaluationSuccess(t *testing.T) {
	store := &mockEvaluationStore{}
	srv := setupEvaluationServer(t, store)
	defer srv.Close()

	// Setup mock expectations
	flagKey := "test-flag"
	namespaceKey := "test-namespace"
	store.On("GetFlag", store.matchContext(), storage.NewResource(namespaceKey, flagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespaceKey,
			Key:          flagKey,
			Enabled:      true,
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRollouts", store.matchContext(), storage.NewResource(namespaceKey, flagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Make request
	payload := map[string]interface{}{
		"flag_key":      flagKey,
		"entity_id":     "user123",
		"namespace_key": namespaceKey,
		"context": map[string]string{
			"country": "US",
		},
	}

	body, err := json.Marshal(payload)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", srv.URL),
		"application/json",
		bytes.NewReader(body),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Assert response
	assert.Equal(t, http.StatusOK, resp.StatusCode)

	var result rpcevaluation.BooleanEvaluationResponse
	err = json.NewDecoder(resp.Body).Decode(&result)
	require.NoError(t, err)

	assert.Equal(t, true, result.Enabled)
	assert.Equal(t, flagKey, result.FlagKey)
	assert.NotEmpty(t, result.RequestDurationMillis)
}

// TestBooleanEvaluationFlagNotFound tests boolean evaluation when flag does not exist
func TestBooleanEvaluationFlagNotFound(t *testing.T) {
	store := &mockEvaluationStore{}
	srv := setupEvaluationServer(t, store)
	defer srv.Close()

	// Setup mock expectations for flag not found
	flagKey := "nonexistent-flag"
	namespaceKey := "test-namespace"

	store.On("GetFlag", store.matchContext(), store.matchAnything()).
		Return(&flipt.Flag{}, fmt.Errorf("flag not found"))

	// Make request
	payload := map[string]interface{}{
		"flag_key":      flagKey,
		"entity_id":     "user123",
		"namespace_key": namespaceKey,
	}

	body, err := json.Marshal(payload)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", srv.URL),
		"application/json",
		bytes.NewReader(body),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Assert that it returns an error status code
	assert.Equal(t, http.StatusInternalServerError, resp.StatusCode)
}

// TestBooleanEvaluationInvalidRequest tests boolean evaluation with invalid JSON
func TestBooleanEvaluationInvalidRequest(t *testing.T) {
	store := &mockEvaluationStore{}
	srv := setupEvaluationServer(t, store)
	defer srv.Close()

	// Send invalid JSON
	invalidJSON := []byte(`{invalid json}`)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", srv.URL),
		"application/json",
		bytes.NewReader(invalidJSON),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Assert that it returns a bad request error
	assert.Equal(t, http.StatusBadRequest, resp.StatusCode)
}

// TestVariantEvaluationSuccess tests a successful variant flag evaluation
func TestVariantEvaluationSuccess(t *testing.T) {
	store := &mockEvaluationStore{}
	srv := setupEvaluationServer(t, store)
	defer srv.Close()

	// Setup mock expectations
	flagKey := "variant-flag"
	namespaceKey := "test-namespace"

	store.On("GetFlag", store.matchContext(), storage.NewResource(namespaceKey, flagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespaceKey,
			Key:          flagKey,
			Enabled:      true,
			Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRules", store.matchContext(), storage.NewResource(namespaceKey, flagKey)).
		Return([]*storage.EvaluationRule{}, nil)

	// Make request
	payload := map[string]interface{}{
		"flag_key":      flagKey,
		"entity_id":     "user123",
		"namespace_key": namespaceKey,
		"context": map[string]string{
			"region": "EU",
		},
	}

	body, err := json.Marshal(payload)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/variant", srv.URL),
		"application/json",
		bytes.NewReader(body),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Assert response
	assert.Equal(t, http.StatusOK, resp.StatusCode)

	var result rpcevaluation.VariantEvaluationResponse
	err = json.NewDecoder(resp.Body).Decode(&result)
	require.NoError(t, err)

	assert.Equal(t, false, result.Match)
	assert.Equal(t, flagKey, result.FlagKey)
	assert.NotEmpty(t, result.RequestDurationMillis)
}

// TestVariantEvaluationFlagNotFound tests variant evaluation when flag does not exist
func TestVariantEvaluationFlagNotFound(t *testing.T) {
	store := &mockEvaluationStore{}
	srv := setupEvaluationServer(t, store)
	defer srv.Close()

	flagKey := "missing-variant"
	namespaceKey := "test-namespace"

	store.On("GetFlag", store.matchContext(), store.matchAnything()).
		Return(&flipt.Flag{}, fmt.Errorf("variant flag not found"))

	// Make request
	payload := map[string]interface{}{
		"flag_key":      flagKey,
		"entity_id":     "user456",
		"namespace_key": namespaceKey,
	}

	body, err := json.Marshal(payload)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/variant", srv.URL),
		"application/json",
		bytes.NewReader(body),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Assert error response
	assert.Equal(t, http.StatusInternalServerError, resp.StatusCode)
}

// TestBatchEvaluationSuccess tests batch evaluation with multiple requests
func TestBatchEvaluationSuccess(t *testing.T) {
	store := &mockEvaluationStore{}
	srv := setupEvaluationServer(t, store)
	defer srv.Close()

	boolFlagKey := "bool-flag"
	variantFlagKey := "variant-flag"
	namespaceKey := "test-namespace"

	// Setup mocks for boolean flag
	store.On("GetFlag", store.matchContext(), storage.NewResource(namespaceKey, boolFlagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespaceKey,
			Key:          boolFlagKey,
			Enabled:      true,
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRollouts", store.matchContext(), storage.NewResource(namespaceKey, boolFlagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Setup mocks for variant flag
	store.On("GetFlag", store.matchContext(), storage.NewResource(namespaceKey, variantFlagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespaceKey,
			Key:          variantFlagKey,
			Enabled:      true,
			Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRules", store.matchContext(), storage.NewResource(namespaceKey, variantFlagKey)).
		Return([]*storage.EvaluationRule{}, nil)

	// Make batch request
	payload := map[string]interface{}{
		"requests": []map[string]interface{}{
			{
				"request_id":    "req1",
				"flag_key":      boolFlagKey,
				"entity_id":     "user123",
				"namespace_key": namespaceKey,
			},
			{
				"request_id":    "req2",
				"flag_key":      variantFlagKey,
				"entity_id":     "user456",
				"namespace_key": namespaceKey,
			},
		},
	}

	body, err := json.Marshal(payload)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/batch", srv.URL),
		"application/json",
		bytes.NewReader(body),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Assert response
	assert.Equal(t, http.StatusOK, resp.StatusCode)

	var result rpcevaluation.BatchEvaluationResponse
	err = json.NewDecoder(resp.Body).Decode(&result)
	require.NoError(t, err)

	assert.Equal(t, 2, len(result.Responses))
	assert.NotEmpty(t, result.RequestDurationMillis)
}

// TestEvaluationNamespaceScoping tests that evaluations are correctly scoped to namespaces
func TestEvaluationNamespaceScoping(t *testing.T) {
	store := &mockEvaluationStore{}
	srv := setupEvaluationServer(t, store)
	defer srv.Close()

	flagKey := "namespace-scoped-flag"
	namespace1 := "namespace-1"
	namespace2 := "namespace-2"

	// Setup mocks for first namespace
	store.On("GetFlag", store.matchContext(), storage.NewResource(namespace1, flagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespace1,
			Key:          flagKey,
			Enabled:      true,
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRollouts", store.matchContext(), storage.NewResource(namespace1, flagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Setup mocks for second namespace
	store.On("GetFlag", store.matchContext(), storage.NewResource(namespace2, flagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespace2,
			Key:          flagKey,
			Enabled:      false,
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRollouts", store.matchContext(), storage.NewResource(namespace2, flagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Evaluate in first namespace
	payload1 := map[string]interface{}{
		"flag_key":      flagKey,
		"entity_id":     "user123",
		"namespace_key": namespace1,
	}

	body1, err := json.Marshal(payload1)
	require.NoError(t, err)

	resp1, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", srv.URL),
		"application/json",
		bytes.NewReader(body1),
	)
	require.NoError(t, err)
	defer resp1.Body.Close()

	var result1 rpcevaluation.BooleanEvaluationResponse
	err = json.NewDecoder(resp1.Body).Decode(&result1)
	require.NoError(t, err)
	assert.Equal(t, true, result1.Enabled)

	// Evaluate in second namespace
	payload2 := map[string]interface{}{
		"flag_key":      flagKey,
		"entity_id":     "user123",
		"namespace_key": namespace2,
	}

	body2, err := json.Marshal(payload2)
	require.NoError(t, err)

	resp2, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", srv.URL),
		"application/json",
		bytes.NewReader(body2),
	)
	require.NoError(t, err)
	defer resp2.Body.Close()

	var result2 rpcevaluation.BooleanEvaluationResponse
	err = json.NewDecoder(resp2.Body).Decode(&result2)
	require.NoError(t, err)
	assert.Equal(t, false, result2.Enabled)
}

// TestBatchEvaluationEmptyRequests tests batch evaluation with empty requests
func TestBatchEvaluationEmptyRequests(t *testing.T) {
	store := &mockEvaluationStore{}
	srv := setupEvaluationServer(t, store)
	defer srv.Close()

	// Make batch request with empty requests array
	payload := map[string]interface{}{
		"requests": []interface{}{},
	}

	body, err := json.Marshal(payload)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/batch", srv.URL),
		"application/json",
		bytes.NewReader(body),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Should return OK with empty responses
	assert.Equal(t, http.StatusOK, resp.StatusCode)

	var result rpcevaluation.BatchEvaluationResponse
	err = json.NewDecoder(resp.Body).Decode(&result)
	require.NoError(t, err)

	assert.Equal(t, 0, len(result.Responses))
}

// TestEvaluationResponseHeaders tests that responses have correct content-type header
func TestEvaluationResponseHeaders(t *testing.T) {
	store := &mockEvaluationStore{}
	srv := setupEvaluationServer(t, store)
	defer srv.Close()

	flagKey := "header-test-flag"
	namespaceKey := "test-namespace"

	store.On("GetFlag", store.matchContext(), storage.NewResource(namespaceKey, flagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespaceKey,
			Key:          flagKey,
			Enabled:      true,
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRollouts", store.matchContext(), storage.NewResource(namespaceKey, flagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Make request
	payload := map[string]interface{}{
		"flag_key":      flagKey,
		"entity_id":     "user123",
		"namespace_key": namespaceKey,
	}

	body, err := json.Marshal(payload)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", srv.URL),
		"application/json",
		bytes.NewReader(body),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Verify response headers
	assert.Equal(t, http.StatusOK, resp.StatusCode)
	assert.NotEmpty(t, resp.Header.Get("Content-Type"))
}

// mockEvaluationStore is a mock implementation of evaluation.Storer
type mockEvaluationStore struct {
	calls map[string]int
	mocks map[string]interface{}
}

func (m *mockEvaluationStore) GetFlag(ctx context.Context, req storage.ResourceRequest) (*flipt.Flag, error) {
	args := m.Called(ctx, req)
	if args.Get(1) == nil {
		return args.Get(0).(*flipt.Flag), nil
	}
	return args.Get(0).(*flipt.Flag), args.Get(1).(error)
}

func (m *mockEvaluationStore) GetEvaluationRules(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRule, error) {
	args := m.Called(ctx, req)
	if args.Get(1) == nil {
