func (m *mockEvaluationStore) GetEvaluationRollouts(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRollout, error) {
	args := m.Called(ctx, req)
	if args.Get(1) == nil {
		return args.Get(0).([]*storage.EvaluationRollout), nil
	}
	return args.Get(0).([]*storage.EvaluationRollout), args.Get(1).(error)
}

func (m *mockEvaluationStore) On(methodName string, arguments ...interface{}) *mockEvaluationStore {
	if m.mocks == nil {
		m.mocks = make(map[string]interface{})
	}
	if m.calls == nil {
		m.calls = make(map[string]int)
	}
	m.mocks[methodName] = arguments
	return m
}

func (m *mockEvaluationStore) Called(args ...interface{}) *mockCallResult {
	return &mockCallResult{args: args}
}

func (m *mockEvaluationStore) matchContext() interface{} {
	// Simple matcher for context
	return context.Background()
}

func (m *mockEvaluationStore) matchAnything() interface{} {
	return nil
}

// mockCallResult is a simple mock result holder
type mockCallResult struct {
	args []interface{}
}

func (r *mockCallResult) Get(index int) interface{} {
	if index < len(r.args) {
		return r.args[index]
	}
	return nil
}

