// TestBatchEvaluationSuccess tests batch evaluation with multiple requests
func TestBatchEvaluationSuccess(t *testing.T) {
	store := &mockEvaluationStore{}
	srv := setupEvaluationServer(t, store)
	defer srv.Close()

	boolFlagKey := "bool-flag"
	variantFlagKey := "variant-flag"
	namespaceKey := "test-namespace"

	// Setup mocks for boolean flag
	store.On("GetFlag", store.matchContext(), storage.NewResource(namespaceKey, boolFlagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespaceKey,
			Key:          boolFlagKey,
			Enabled:      true,
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRollouts", store.matchContext(), storage.NewResource(namespaceKey, boolFlagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Setup mocks for variant flag
	store.On("GetFlag", store.matchContext(), storage.NewResource(namespaceKey, variantFlagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespaceKey,
			Key:          variantFlagKey,
			Enabled:      true,
			Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRules", store.matchContext(), storage.NewResource(namespaceKey, variantFlagKey)).
		Return([]*storage.EvaluationRule{}, nil)

	// Make batch request
	payload := map[string]interface{}{
		"requests": []map[string]interface{}{
			{
				"request_id":    "req1",
				"flag_key":      boolFlagKey,
				"entity_id":     "user123",
				"namespace_key": namespaceKey,
			},
			{
				"request_id":    "req2",
				"flag_key":      variantFlagKey,
				"entity_id":     "user456",
				"namespace_key": namespaceKey,
			},
		},
	}

