	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Assert response
	assert.Equal(t, http.StatusOK, resp.StatusCode)

	var result rpcevaluation.BatchEvaluationResponse
	err = json.NewDecoder(resp.Body).Decode(&result)
	require.NoError(t, err)

	assert.Equal(t, 2, len(result.Responses))
	assert.NotEmpty(t, result.RequestDurationMillis)
}

// TestEvaluationNamespaceScoping tests that evaluations are correctly scoped to namespaces
func TestEvaluationNamespaceScoping(t *testing.T) {
	store := &mockEvaluationStore{}
	srv := setupEvaluationServer(t, store)
	defer srv.Close()

	flagKey := "namespace-scoped-flag"
	namespace1 := "namespace-1"
	namespace2 := "namespace-2"

	// Setup mocks for first namespace
	store.On("GetFlag", store.matchContext(), storage.NewResource(namespace1, flagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespace1,
			Key:          flagKey,
			Enabled:      true,
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRollouts", store.matchContext(), storage.NewResource(namespace1, flagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Setup mocks for second namespace
	store.On("GetFlag", store.matchContext(), storage.NewResource(namespace2, flagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespace2,
			Key:          flagKey,
			Enabled:      false,
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRollouts", store.matchContext(), storage.NewResource(namespace2, flagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Evaluate in first namespace
	payload1 := map[string]interface{}{
		"flag_key":      flagKey,
		"entity_id":     "user123",
		"namespace_key": namespace1,
	}

	body1, err := json.Marshal(payload1)
	require.NoError(t, err)

	resp1, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", srv.URL),
		"application/json",
