		"flag_key":      flagKey,
		"entity_id":     "user123",
		"namespace_key": namespace2,
	}

	body2, err := json.Marshal(payload2)
	require.NoError(t, err)

	resp2, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", srv.URL),
		"application/json",
		bytes.NewReader(body2),
	)
	require.NoError(t, err)
	defer resp2.Body.Close()

	var result2 rpcevaluation.BooleanEvaluationResponse
	err = json.NewDecoder(resp2.Body).Decode(&result2)
	require.NoError(t, err)
	assert.Equal(t, false, result2.Enabled)
}

