		Return(&flipt.Flag{
			NamespaceKey: namespaceKey,
			Key:          variantFlagKey,
			Enabled:      true,
			Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRules", mock.Anything, storage.NewResource(namespaceKey, variantFlagKey)).
		Return([]*storage.EvaluationRule{}, nil)

	// Make batch request
	payload := map[string]interface{}{
